import { Link } from 'react-router-dom';

function Navbar() {
  return (
    <header className="navbar">
      <div className="navbar-inner">
        <div className="navbar-title">
          OS Simulator Toolkit
          <span className="navbar-chip">Learning Lab</span>
        </div>
        <nav className="navbar-links">
          <Link to="/">Home</Link>
          <Link to="/cpu-scheduling">CPU</Link>
          <Link to="/page-replacement">Memory</Link>
          <Link to="/deadlock-avoidance">Deadlock</Link>
          <Link to="/disk-scheduling">Disk</Link>
        </nav>
      </div>
    </header>
  );
}

export default Navbar;
